# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for a multi-user team collaboration tool.
It manages users, projects, tasks, threaded messages with attachments,
per-user performance metrics, and exportable progress/performance reports.

The public surface is the :class:`TeamCollaborationManager` facade. Internally
the work is split into focused repositories/services (users, projects, tasks,
messages, performance, reports) that all share a single re-entrant lock and a
single shared state container so that identifiers are globally unique and every
mutation is serialized.

Only the Python standard library is used.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple

__all__ = [
    "TeamCollaborationManager",
    "TaskStatus",
    "UserRole",
    "ReportFormat",
    "ReportType",
    "TeamCollaborationError",
    "ValidationError",
    "NotFoundError",
    "AuthorizationError",
    "DuplicateError",
    "ConflictError",
    "Attachment",
    "User",
    "Project",
    "Task",
    "Message",
    "Rating",
]


# ---------------------------------------------------------------------------
# Sentinel for "argument not supplied" so callers can distinguish an explicit
# ``None`` (e.g. clearing a deadline) from "leave unchanged" on update calls.
# ---------------------------------------------------------------------------
_UNSET = object()


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states a task can be in."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Roles a registered user can hold."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Categories of report the manager can produce."""

    TEAM_PERFORMANCE = "team_performance"
    PROJECT_PROGRESS = "project_progress"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied input fails a validation rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an action conflicts with existing state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A binary file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime
    data: bytes = b""


@dataclass
class User:
    """A registered collaborator."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A unit of work owned by a user and worked on by the team."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A single piece of work belonging to a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    """A (possibly threaded) message attached to a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating awarded from one user to another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Shared, lock-guarded state container
# ---------------------------------------------------------------------------
class _State:
    """Holds every mutable collection plus the shared lock, clock and id source.

    All repositories receive the *same* instance, which is how ids stay globally
    unique and how cross-entity operations (cascading deletes, dependency
    checks) remain consistent under a single lock.
    """

    def __init__(self, now: Callable[[], datetime]) -> None:
        self.lock = threading.RLock()
        self._now = now
        self._next_id = 1

        # Primary stores keyed by id.
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        # Uniqueness indexes (lower-cased value -> user id).
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}

        # Relationship indexes.
        self.tasks_by_project: Dict[int, List[int]] = {}
        self.tasks_by_assignee: Dict[int, set] = {}
        self.messages_by_project: Dict[int, List[int]] = {}
        self.messages_by_task: Dict[int, List[int]] = {}
        self.ratings_by_ratee: Dict[int, List[int]] = {}

    # -- clock / id helpers -------------------------------------------------
    def now(self) -> datetime:
        return self._now()

    def next_id(self) -> int:
        new_id = self._next_id
        self._next_id += 1
        return new_id

    # -- existence helpers (caller already holds the lock) ------------------
    def require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message


def _clone(obj):
    """Return a deep copy so callers can never mutate stored state."""

    return copy.deepcopy(obj)


# ---------------------------------------------------------------------------
# Small validation helpers
# ---------------------------------------------------------------------------
def _require_non_empty(value: str, field_name: str) -> str:
    if not isinstance(value, str) or not value.strip():
        raise ValidationError("{0} must be a non-empty string".format(field_name))
    return value.strip()


def _validate_email(email: str) -> str:
    if not isinstance(email, str) or not email.strip():
        raise ValidationError("email must be a non-empty string")
    cleaned = email.strip()
    if "@" not in cleaned:
        raise ValidationError("email must contain '@'")
    return cleaned


def _is_completed(task: Task) -> bool:
    return task.status == TaskStatus.COMPLETED


def _task_duration_seconds(task: Task) -> Optional[float]:
    if task.started_at is not None and task.completed_at is not None:
        return (task.completed_at - task.started_at).total_seconds()
    return None


def _completion_rate(tasks: List[Task]) -> float:
    if not tasks:
        return 0.0
    completed = sum(1 for task in tasks if _is_completed(task))
    return completed / len(tasks)


def _average_completion_time(tasks: List[Task]) -> Optional[float]:
    durations = [
        _task_duration_seconds(task)
        for task in tasks
        if _is_completed(task) and _task_duration_seconds(task) is not None
    ]
    if not durations:
        return None
    return sum(durations) / len(durations)


# ---------------------------------------------------------------------------
# User repository
# ---------------------------------------------------------------------------
class _UserRepository:
    def __init__(self, state: _State) -> None:
        self._state = state
        self._lock = state.lock

    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            clean_username = _require_non_empty(username, "username")
            clean_email = _validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            ukey = clean_username.lower()
            ekey = clean_email.lower()
            if ukey in self._state.username_index:
                raise DuplicateError("username '{0}' already exists".format(clean_username))
            if ekey in self._state.email_index:
                raise DuplicateError("email '{0}' already exists".format(clean_email))

            user_id = self._state.next_id()
            user = User(
                id=user_id,
                username=clean_username,
                email=clean_email,
                role=role,
                created_at=self._state.now(),
            )
            self._state.users[user_id] = user
            self._state.username_index[ukey] = user_id
            self._state.email_index[ekey] = user_id
            return _clone(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return _clone(self._state.require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [
                _clone(self._state.users[uid])
                for uid in sorted(self._state.users)
            ]

    def update_user(self, user_id, username=_UNSET, email=_UNSET, role=_UNSET) -> User:
        with self._lock:
            user = self._state.require_user(user_id)

            new_username = None
            new_email = None
            if username is not _UNSET:
                new_username = _require_non_empty(username, "username")
                ukey = new_username.lower()
                if ukey != user.username.lower() and ukey in self._state.username_index:
                    raise DuplicateError(
                        "username '{0}' already exists".format(new_username)
                    )
            if email is not _UNSET:
                new_email = _validate_email(email)
                ekey = new_email.lower()
                if ekey != user.email.lower() and ekey in self._state.email_index:
                    raise DuplicateError("email '{0}' already exists".format(new_email))
            if role is not _UNSET and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not _UNSET:
                self._state.username_index.pop(user.username.lower(), None)
                user.username = new_username
                self._state.username_index[new_username.lower()] = user_id
            if email is not _UNSET:
                self._state.email_index.pop(user.email.lower(), None)
                user.email = new_email
                self._state.email_index[new_email.lower()] = user_id
            if role is not _UNSET:
                user.role = role
            return _clone(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            user = self._state.require_user(user_id)

            for project in self._state.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "user {0} owns project {1}".format(user_id, project.id)
                    )

            for task_id in self._state.tasks_by_assignee.get(user_id, set()):
                task = self._state.tasks.get(task_id)
                if task is not None and not _is_completed(task):
                    raise ConflictError(
                        "user {0} has open task {1}".format(user_id, task_id)
                    )

            del self._state.users[user_id]
            self._state.username_index.pop(user.username.lower(), None)
            self._state.email_index.pop(user.email.lower(), None)
            self._state.tasks_by_assignee.pop(user_id, None)


# ---------------------------------------------------------------------------
# Project repository
# ---------------------------------------------------------------------------
class _ProjectRepository:
    def __init__(self, state: _State) -> None:
        self._state = state
        self._lock = state.lock

    def create_project(self, name, start_date, end_date, owner_id, description="") -> Project:
        with self._lock:
            self._state.require_user(owner_id)
            clean_name = _require_non_empty(name, "name")
            if end_date < start_date:
                raise ValidationError("end_date must not be before start_date")

            project_id = self._state.next_id()
            project = Project(
                id=project_id,
                name=clean_name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._state.now(),
            )
            self._state.projects[project_id] = project
            self._state.tasks_by_project[project_id] = []
            self._state.messages_by_project[project_id] = []
            return _clone(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return _clone(self._state.require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                _clone(self._state.projects[pid])
                for pid in sorted(self._state.projects)
            ]

    def update_project(
        self,
        project_id,
        name=_UNSET,
        start_date=_UNSET,
        end_date=_UNSET,
        description=_UNSET,
    ) -> Project:
        with self._lock:
            project = self._state.require_project(project_id)

            new_name = None
            if name is not _UNSET:
                new_name = _require_non_empty(name, "name")

            effective_start = project.start_date if start_date is _UNSET else start_date
            effective_end = project.end_date if end_date is _UNSET else end_date
            if effective_end < effective_start:
                raise ValidationError("end_date must not be before start_date")

            if name is not _UNSET:
                project.name = new_name
            if start_date is not _UNSET:
                project.start_date = start_date
            if end_date is not _UNSET:
                project.end_date = end_date
            if description is not _UNSET:
                project.description = description or ""
            return _clone(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._state.require_project(project_id)

            for task_id in list(self._state.tasks_by_project.get(project_id, [])):
                task = self._state.tasks.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    assignee_tasks = self._state.tasks_by_assignee.get(task.assignee_id)
                    if assignee_tasks is not None:
                        assignee_tasks.discard(task_id)
                for message_id in list(self._state.messages_by_task.get(task_id, [])):
                    self._state.messages.pop(message_id, None)
                self._state.messages_by_task.pop(task_id, None)
            self._state.tasks_by_project.pop(project_id, None)

            for message_id in list(self._state.messages_by_project.get(project_id, [])):
                self._state.messages.pop(message_id, None)
            self._state.messages_by_project.pop(project_id, None)

            self._state.projects.pop(project_id, None)


# ---------------------------------------------------------------------------
# Task repository
# ---------------------------------------------------------------------------
class _TaskRepository:
    def __init__(self, state: _State) -> None:
        self._state = state
        self._lock = state.lock

    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            project = self._state.require_project(project_id)
            if assignee_id is not None:
                self._state.require_user(assignee_id)
            clean_title = _require_non_empty(title, "title")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not be before project start")

            task_id = self._state.next_id()
            task = Task(
                id=task_id,
                project_id=project_id,
                title=clean_title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._state.now(),
            )
            self._state.tasks[task_id] = task
            self._state.tasks_by_project.setdefault(project_id, []).append(task_id)
            if assignee_id is not None:
                self._state.tasks_by_assignee.setdefault(assignee_id, set()).add(task_id)
            return _clone(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return _clone(self._state.require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._state.require_project(project_id)
            task_ids = self._state.tasks_by_project.get(project_id, [])
            return [_clone(self._state.tasks[tid]) for tid in sorted(task_ids)]

    def list_tasks_by_assignee(self, user_id) -> List[Task]:
        with self._lock:
            self._state.require_user(user_id)
            task_ids = self._state.tasks_by_assignee.get(user_id, set())
            return [_clone(self._state.tasks[tid]) for tid in sorted(task_ids)]

    def _set_assignee(self, task: Task, new_assignee_id: Optional[int]) -> None:
        if task.assignee_id is not None:
            current = self._state.tasks_by_assignee.get(task.assignee_id)
            if current is not None:
                current.discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self._state.tasks_by_assignee.setdefault(new_assignee_id, set()).add(task.id)

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._state.require_task(task_id)
            self._state.require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return _clone(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._state.require_task(task_id)
            self._state.require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return _clone(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._state.require_task(task_id)
            self._set_assignee(task, None)
            return _clone(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._state.require_task(task_id)
            if deadline is not None:
                project = self._state.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not be before project start")
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._state.require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._state.now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return _clone(task)


# ---------------------------------------------------------------------------
# Message repository
# ---------------------------------------------------------------------------
class _MessageRepository:
    def __init__(self, state: _State) -> None:
        self._state = state
        self._lock = state.lock

    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        with self._lock:
            self._state.require_user(author_id)

            has_project = project_id is not None
            has_task = task_id is not None
            if has_project == has_task:
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided"
                )
            if has_project:
                self._state.require_project(project_id)
            else:
                self._state.require_task(task_id)
            if parent_id is not None:
                self._state.require_message(parent_id)

            attachment_specs: List[Tuple[str, bytes]] = list(attachments or [])
            if not (isinstance(body, str) and body.strip()) and not attachment_specs:
                raise ValidationError("message body must be non-empty without attachments")

            now = self._state.now()
            attachment_objs = [
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                    data=bytes(data),
                )
                for filename, data in attachment_specs
            ]

            message_id = self._state.next_id()
            message = Message(
                id=message_id,
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=now,
                edited_at=None,
            )
            self._state.messages[message_id] = message
            if has_project:
                self._state.messages_by_project.setdefault(project_id, []).append(message_id)
            else:
                self._state.messages_by_task.setdefault(task_id, []).append(message_id)
            return _clone(message)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._state.require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            if not (isinstance(new_body, str) and new_body.strip()) and not message.attachments:
                raise ValidationError("message body must be non-empty without attachments")
            message.body = new_body
            message.edited_at = self._state.now()
            return _clone(message)

    def add_attachment(self, message_id, uploader_id, filename, content) -> Message:
        with self._lock:
            message = self._state.require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may attach to this message")
            if not (isinstance(filename, str) and filename.strip()):
                raise ValidationError("filename must be a non-empty string")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(content),
                    uploaded_by=uploader_id,
                    uploaded_at=self._state.now(),
                    data=bytes(content),
                )
            )
            return _clone(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._state.require_project(project_id)
            message_ids = self._state.messages_by_project.get(project_id, [])
            return [_clone(self._state.messages[mid]) for mid in sorted(message_ids)]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._state.require_task(task_id)
            message_ids = self._state.messages_by_task.get(task_id, [])
            return [_clone(self._state.messages[mid]) for mid in sorted(message_ids)]

    def delete_message(self, message_id, requester_id) -> None:
        with self._lock:
            message = self._state.require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete this message")
            self._state.messages.pop(message_id, None)
            if message.project_id is not None:
                bucket = self._state.messages_by_project.get(message.project_id)
                if bucket is not None and message_id in bucket:
                    bucket.remove(message_id)
            if message.task_id is not None:
                bucket = self._state.messages_by_task.get(message.task_id)
                if bucket is not None and message_id in bucket:
                    bucket.remove(message_id)


# ---------------------------------------------------------------------------
# Performance service
# ---------------------------------------------------------------------------
class _PerformanceService:
    def __init__(self, state: _State) -> None:
        self._state = state
        self._lock = state.lock

    def _assigned_tasks(self, user_id: int) -> List[Task]:
        task_ids = self._state.tasks_by_assignee.get(user_id, set())
        return [self._state.tasks[tid] for tid in task_ids if tid in self._state.tasks]

    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._state.require_user(user_id)
            return _completion_rate(self._assigned_tasks(user_id))

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._state.require_user(user_id)
            return _average_completion_time(self._assigned_tasks(user_id))

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            self._state.require_user(rater_id)
            self._state.require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool) or not (1 <= score <= 5):
                raise ValidationError("score must be an integer between 1 and 5")
            if task_id is not None:
                self._state.require_task(task_id)

            rating_id = self._state.next_id()
            rating = Rating(
                id=rating_id,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._state.now(),
            )
            self._state.ratings[rating_id] = rating
            self._state.ratings_by_ratee.setdefault(ratee_id, []).append(rating_id)
            return _clone(rating)

    def _ratings_for(self, user_id: int) -> List[Rating]:
        rating_ids = self._state.ratings_by_ratee.get(user_id, [])
        return [self._state.ratings[rid] for rid in rating_ids if rid in self._state.ratings]

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._state.require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [_clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._state.require_user(user_id)
            tasks = self._assigned_tasks(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": _completion_rate(tasks),
                "average_completion_time": _average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


# ---------------------------------------------------------------------------
# Report service
# ---------------------------------------------------------------------------
class _ReportService:
    def __init__(self, state: _State, performance: _PerformanceService) -> None:
        self._state = state
        self._lock = state.lock
        self._performance = performance

    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            self._state.require_project(project_id)
            task_ids = self._state.tasks_by_project.get(project_id, [])
            tasks = [self._state.tasks[tid] for tid in task_ids if tid in self._state.tasks]
            now = self._state.now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    stats = per_assignee.setdefault(
                        task.assignee_id, {"total_tasks": 0, "completed_tasks": 0}
                    )
                    stats["total_tasks"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        stats["completed_tasks"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": len(tasks),
                "status_counts": status_counts,
                "completion_rate": _completion_rate(tasks),
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def _user_row(self, user_id: int, tasks: List[Task]) -> dict:
        ratings = self._performance._ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        return {
            "user_id": user_id,
            "total_tasks": len(tasks),
            "completed_tasks": sum(1 for t in tasks if _is_completed(t)),
            "completion_rate": _completion_rate(tasks),
            "average_completion_time": _average_completion_time(tasks),
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._state.require_project(project_id)
                scope_ids = self._state.tasks_by_project.get(project_id, [])
                tasks = [
                    self._state.tasks[tid] for tid in scope_ids if tid in self._state.tasks
                ]
            else:
                tasks = list(self._state.tasks.values())

            grouped: Dict[int, List[Task]] = {}
            for task in tasks:
                if task.assignee_id is not None:
                    grouped.setdefault(task.assignee_id, []).append(task)

            rows = [
                self._user_row(user_id, grouped[user_id])
                for user_id in sorted(grouped)
            ]
            columns = [
                "user_id",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "columns": columns,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            self._state.require_user(user_id)
            task_ids = self._state.tasks_by_assignee.get(user_id, set())
            tasks = [self._state.tasks[tid] for tid in sorted(task_ids) if tid in self._state.tasks]

            ratings = self._performance._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )
            task_rows = [
                {
                    "id": task.id,
                    "title": task.title,
                    "status": task.status.value,
                    "project_id": task.project_id,
                    "deadline": task.deadline,
                    "started_at": task.started_at,
                    "completed_at": task.completed_at,
                }
                for task in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": len(tasks),
                "completed_tasks": sum(1 for t in tasks if _is_completed(t)),
                "in_progress_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
                ),
                "not_started_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.NOT_STARTED
                ),
                "completion_rate": _completion_rate(tasks),
                "average_completion_time": _average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    # -- export ------------------------------------------------------------
    def export_report(self, report, report_format):
        if not isinstance(report, dict):
            raise ValidationError("report must be a mapping")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if report_format == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    @staticmethod
    def _to_csv(report: dict) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        rows = report.get("rows")
        columns = report.get("columns")
        if isinstance(rows, list) and isinstance(columns, list):
            writer.writerow(columns)
            for row in rows:
                writer.writerow([row.get(col, "") for col in columns])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                if isinstance(value, dict):
                    for sub_key, sub_value in value.items():
                        writer.writerow(["{0}.{1}".format(key, sub_key), sub_value])
                elif isinstance(value, list):
                    writer.writerow([key, "{0} items".format(len(value))])
                else:
                    writer.writerow([key, value])
        return buffer.getvalue()

    @classmethod
    def _to_pdf(cls, report: dict) -> bytes:
        title = str(report.get("report_type", "report"))
        lines = cls._report_lines(report)
        return _build_pdf(title, lines)

    @staticmethod
    def _report_lines(report: dict) -> List[str]:
        lines: List[str] = []
        for key, value in report.items():
            if isinstance(value, dict):
                lines.append("{0}:".format(key))
                for sub_key, sub_value in value.items():
                    lines.append("  {0}: {1}".format(sub_key, sub_value))
            elif isinstance(value, list):
                lines.append("{0}: {1} items".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return lines


# ---------------------------------------------------------------------------
# Minimal PDF rendering (no third-party dependencies)
# ---------------------------------------------------------------------------
def _pdf_escape(text: str) -> str:
    encoded = text.encode("latin-1", "replace").decode("latin-1")
    return encoded.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")


def _build_pdf(title: str, lines: List[str]) -> bytes:
    """Build a small but structurally valid single-page PDF document."""

    text_lines = [title, ""] + list(lines)
    content_parts = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
    for index, line in enumerate(text_lines):
        if index > 0:
            content_parts.append("T*")
        content_parts.append("({0}) Tj".format(_pdf_escape(line)))
    content_parts.append("ET")
    stream = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        ),
        b"<< /Length " + str(len(stream)).encode("ascii") + b" >>\nstream\n" + stream + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    out = bytearray(b"%PDF-1.4\n")
    offsets: List[int] = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(out))
        out += "{0} 0 obj\n".format(number).encode("ascii")
        out += body
        out += b"\nendobj\n"

    xref_position = len(out)
    size = len(objects) + 1
    out += "xref\n0 {0}\n".format(size).encode("ascii")
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    out += b"trailer\n"
    out += "<< /Size {0} /Root 1 0 R >>\n".format(size).encode("ascii")
    out += b"startxref\n"
    out += "{0}\n".format(xref_position).encode("ascii")
    out += b"%%EOF"
    return bytes(out)


